from kivy.lang import Builderfrom kivymd.app import MDAppfrom kivy.uix.camera import CameraKV = '''BoxLayout:    orientation: 'vertical'    MDTopAppBar:        title: "CivilPy Inspection App"        md_bg_color: app.theme_cls.primary_color        elevation: 10    Camera:        id: camera        resolution: (640, 480)        play: True    MDFloatingActionButton:        icon: "camera"        md_bg_color: app.theme_cls.primary_color        pos_hint: {"center_x": 0.5}        on_press: camera.play = not camera.play  # Toggle play attribute to start/stop camera'''class MainApp(MDApp):    def build(self):        return Builder.load_string(KV)if __name__ == "__main__":    MainApp().run()